     1→import { Pool } from "pg";
     2→import { PrismaPg } from "@prisma/adapter-pg";
     3→import { PrismaClient } from "../generated/client/wasm";
     4→
     5→const globalForPrisma = globalThis as unknown as {
     6→  prisma: PrismaClient | undefined;
     7→};
     8→
     9→function createPrismaClient() {
    10→  // Use DATABASE_URL (pgbouncer pooled) for runtime queries in serverless.
    11→  // DIRECT_URL is only for migrations (prisma db push/migrate).
    12→  const url = process.env.DATABASE_URL ?? process.env.DIRECT_URL ?? "";
    13→  const pool = new Pool({
    14→    connectionString: url,
    15→    max: 1,
    16→    min: 0,
    17→    idleTimeoutMillis: 5000,         // release connections quickly — prevents stale connections on warm Lambda reuse
    18→    connectionTimeoutMillis: 10000,  // fail fast if can't connect
    19→    allowExitOnIdle: true,           // let Lambda exit cleanly
    20→    ssl: { rejectUnauthorized: false },
    21→  });
    22→  const adapter = new PrismaPg(pool);
    23→  return new PrismaClient({ adapter });
    24→}
    25→
    26→export const prisma = globalForPrisma.prisma ?? createPrismaClient();
    27→
    28→if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;
    29→
    30→export * from "../generated/client/wasm";
    31→

