     1→import { NextResponse } from "next/server";
     2→import { requireStudent } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { Client } from "@upstash/qstash";
     5→import { redis, CACHE_KEYS } from "@/lib/redis";
     6→import { synthesizeProfile } from "@/lib/synthesize";
     7→
     8→export const maxDuration = 60;
     9→
    10→function getQStash() {
    11→  return new Client({ token: process.env.QSTASH_TOKEN! });
    12→}
    13→
    14→export async function POST(
    15→  _req: Request,
    16→  { params }: { params: Promise<{ id: string }> }
    17→) {
    18→  try {
    19→    const student = await requireStudent();
    20→    const { id } = await params;
    21→
    22→    const session = await prisma.reflectionSession.findFirst({
    23→      where: { id, studentId: student.id },
    24→    });
    25→
    26→    if (!session) {
    27→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    28→    }
    29→
    30→    if (session.completedAt) {
    31→      return NextResponse.json({ error: "Session already submitted" }, { status: 400 });
    32→    }
    33→
    34→    // Mark session as complete
    35→    const now = new Date();
    36→    const durationSeconds = Math.floor(
    37→      (now.getTime() - session.createdAt.getTime()) / 1000
    38→    );
    39→
    40→    await prisma.reflectionSession.update({
    41→      where: { id },
    42→      data: { completedAt: now, durationSeconds },
    43→    });
    44→
    45→    // Run synthesis directly (primary path — no external service dependency)
    46→    try {
    47→      const [activities, reflections, previousProfile] = await Promise.all([
    48→        prisma.activity.findMany({
    49→          where: { studentId: student.id },
    50→          orderBy: { createdAt: "asc" },
    51→        }),
    52→        prisma.reflection.findMany({
    53→          where: { studentId: student.id },
    54→          orderBy: { createdAt: "asc" },
    55→        }),
    56→        prisma.signalProfile.findFirst({
    57→          where: { studentId: student.id },
    58→          orderBy: { createdAt: "desc" },
    59→        }),
    60→      ]);
    61→
    62→      const synthesis = await synthesizeProfile({
    63→        studentId: student.id,
    64→        sessionId: id,
    65→        activities: activities.map((a) => ({
    66→          ...a,
    67→          hoursPerWeek: a.hoursPerWeek ? Number(a.hoursPerWeek) : null,
    68→        })),
    69→        reflections,
    70→        previousProfile,
    71→      });
    72→
    73→      await prisma.signalProfile.create({
    74→        data: {
    75→          studentId: student.id,
    76→          interestClusters: synthesis.interestClusters,
    77→          characterSignals: synthesis.characterSignals,
    78→          trajectoryShifts: synthesis.trajectoryShifts,
    79→          gapDetection: synthesis.gapDetection,
    80→          breadthScore: synthesis.breadthScore,
    81→          compressedSummary: synthesis.compressedSummary,
    82→          lastSynthesizedAt: new Date(),
    83→        },
    84→      });
    85→
    86→      await Promise.all([
    87→        redis.del(CACHE_KEYS.signalProfile(student.id)),
    88→        redis.del(CACHE_KEYS.personalizedMap(student.id)),
    89→      ]).catch(() => {});
    90→    } catch (e) {
    91→      console.error("Direct synthesis failed:", e);
    92→      // Enqueue QStash as fallback so synthesis retries asynchronously
    93→      if (process.env.QSTASH_TOKEN) {
    94→        try {
    95→          const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
    96→          await getQStash().publishJSON({
    97→            url: `${appUrl}/api/webhooks/qstash`,
    98→            body: {
    99→              type: "POST_SESSION_SYNTHESIS",
   100→              data: { studentId: student.id, sessionId: id },
   101→              triggeredAt: now.toISOString(),
   102→            },
   103→            delay: 10,
   104→          });
   105→        } catch (qe) {
   106→          console.error("QStash fallback also failed:", qe);
   107→        }
   108→      }
   109→    }
   110→
   111→    return NextResponse.json({ success: true, completedAt: now });
   112→  } catch (error) {
   113→    const message = error instanceof Error ? error.message : "Unknown error";
   114→    return NextResponse.json({ error: message }, { status: 400 });
   115→  }
   116→}
