   122→async function handleWeeklyNudgeSweep() {
   123→  const now = new Date();
   124→  const cutoff90Days = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
   125→  const cutoff48Hours = new Date(now.getTime() - 48 * 60 * 60 * 1000);
   126→  const cutoff72Hours = new Date(now.getTime() - 72 * 60 * 60 * 1000);
   127→
   128→  // Get all students with notification preferences enabled
   129→  const students = await prisma.student.findMany({
   130→    where: { onboardingCompleted: true },
   131→    include: {
   132→      notificationPrefs: true,
   133→      sessions: {
   134→        orderBy: { createdAt: "desc" },
   135→        take: 1,
   136→        select: { completedAt: true, createdAt: true },
   137→      },
   138→      notifications: {
   139→        where: {
   140→          type: "REFLECTION_NUDGE",
   141→          createdAt: { gte: cutoff48Hours },
   142→        },
   143→        take: 1,
   144→      },
   145→      signalProfiles: {
   146→        orderBy: { createdAt: "desc" },
   147→        take: 1,
   148→        select: { compressedSummary: true },
   149→      },
   150→    },
   151→  });
   152→
   153→  const weekKey = `${now.getFullYear()}-W${Math.ceil(now.getDate() / 7)}`;
   154→
   155→  for (const student of students) {
   156→    const prefs = student.notificationPrefs;
   157→    if (!prefs?.reflectionNudges) continue;
   158→
   159→    // Check weekly cap
   160→    const weeklyCount = (await redis.get(
   161→      `notif-count:${student.id}:${weekKey}`
   162→    )) as number | null;
   163→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
   164→
   165→    // Check 48hr cooldown
   166→    if (student.notifications.length > 0) continue;
   167→
   168→    // Check 72hr post-session cooldown
   169→    const lastSession = student.sessions[0];
   170→    if (lastSession?.completedAt) {
   171→      const sessionCompletedAt = new Date(lastSession.completedAt);
   172→      if (sessionCompletedAt > cutoff72Hours) continue;
   173→
   174→      // Only nudge if it's been more than 35 days (approaching monthly)
   175→      const daysSinceSession = Math.floor(
   176→        (now.getTime() - sessionCompletedAt.getTime()) / (1000 * 60 * 60 * 24)
   177→      );
   178→      if (daysSinceSession < 25) continue;
   179→    }
   180→
   181→    // Check quiet hours
   182→    const hour = now.getHours();
   183→    const quietStart = parseInt(prefs.quietHoursStart?.split(":")[0] ?? "21");
   184→    const quietEnd = parseInt(prefs.quietHoursEnd?.split(":")[0] ?? "8");
   185→    const inQuietHours =
   186→      quietStart > quietEnd
   187→        ? hour >= quietStart || hour < quietEnd
   188→        : hour >= quietStart && hour < quietEnd;
   189→    if (inQuietHours) continue;
   190→
   191→    // Generate personalized notification
   192→    try {
   193→      const content = await aiService.generateNotification({
   194→        studentId: student.id,
   195→        triggerType: "REFLECTION_NUDGE",
   196→        compressedSummary:
   197→          student.signalProfiles[0]?.compressedSummary ?? undefined,
   198→      });
   199→
   200→      await prisma.notification.create({
   201→        data: {
   202→          studentId: student.id,
   203→          type: "REFLECTION_NUDGE",
   204→          title: content.title,
   205→          body: content.body,
   206→        },
   207→      });
   208→
   209→      // Increment weekly count
   210→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
   211→      await redis.expire(
   212→        `notif-count:${student.id}:${weekKey}`,
   213→        60 * 60 * 24 * 7
   214→      );
   215→    } catch {
   216→      // Log and continue
   217→      console.error(`Failed to generate nudge for student ${student.id}`);
   218→    }
   219→  }
   220→}
