     1→import { NextResponse } from "next/server";
     2→import { requireStudent } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { redis, CACHE_KEYS, CACHE_TTL } from "@/lib/redis";
     5→
     6→export async function GET() {
     7→  try {
     8→    const student = await requireStudent();
     9→
    10→    // Check cache
    11→    const cached = await redis.get(CACHE_KEYS.personalizedMap(student.id));
    12→    if (cached) {
    13→      return NextResponse.json(cached);
    14→    }
    15→
    16→    // Get signal profile for embedding-based search
    17→    const signalProfile = await prisma.signalProfile.findFirst({
    18→      where: { studentId: student.id },
    19→      orderBy: { createdAt: "desc" },
    20→    });
    21→
    22→    let nodes;
    23→    let personalizedNodeIds: string[] = [];
    24→
    25→    if (signalProfile?.compressedSummary) {
    26→      // Use pgvector similarity search
    27→      // Generate embedding via AI service, then query
    28→      try {
    29→        const aiServiceUrl = process.env.AI_SERVICE_URL;
    30→        const aiServiceKey = process.env.AI_SERVICE_SECRET_KEY;
    31→
    32→        const embeddingResponse = await fetch(
    33→          `${aiServiceUrl}/embed`,
    34→          {
    35→            method: "POST",
    36→            headers: {
    37→              "Content-Type": "application/json",
    38→              "X-Service-Key": aiServiceKey!,
    39→            },
    40→            body: JSON.stringify({ text: signalProfile.compressedSummary }),
    41→          }
    42→        );
    43→
    44→        if (embeddingResponse.ok) {
    45→          const { embedding } = await embeddingResponse.json() as { embedding: number[] };
    46→          const embeddingStr = `[${embedding.join(",")}]`;
    47→
    48→          // pgvector similarity search (raw query needed for vector ops)
    49→          const similarNodes = await prisma.$queryRaw<
    50→            Array<{ id: string; similarity: number }>
    51→          >`
    52→            SELECT id, 1 - (embedding <-> ${embeddingStr}::vector) as similarity
    53→            FROM "MapNode"
    54→            WHERE embedding IS NOT NULL
    55→            ORDER BY embedding <-> ${embeddingStr}::vector
    56→            LIMIT 50
    57→          `;
    58→
    59→          personalizedNodeIds = similarNodes.map((n) => n.id);
    60→
    61→          nodes = await prisma.mapNode.findMany({
    62→            where: { id: { in: personalizedNodeIds } },
    63→            select: {
    64→              id: true,
    65→              type: true,
    66→              label: true,
    67→              description: true,
    68→              metadata: true,
    69→              parentId: true,
    70→              createdAt: true,
    71→              updatedAt: true,
    72→            },
    73→          });
    74→
    75→          // Inject similarity scores
    76→          const simMap = new Map(
    77→            similarNodes.map((n) => [n.id, n.similarity])
    78→          );
    79→          nodes = nodes.map((n) => ({
    80→            ...n,
    81→            similarity: simMap.get(n.id) ?? 0,
    82→            isPersonalized: true,
    83→          }));
    84→        }
    85→      } catch {
    86→        // Fall through to non-personalized
    87→      }
    88→    }
    89→
    90→    if (!nodes || nodes.length === 0) {
    91→      // Fallback: return all nodes without personalization
    92→      nodes = await prisma.mapNode.findMany({
    93→        select: {
    94→          id: true,
    95→          type: true,
    96→          label: true,
    97→          description: true,
    98→          metadata: true,
    99→          parentId: true,
   100→          createdAt: true,
   101→          updatedAt: true,
   102→        },
   103→        take: 100,
   104→        orderBy: { label: "asc" },
   105→      });
   106→    }
   107→
   108→    // Get edges for these nodes
   109→    const nodeIds = nodes.map((n) => n.id);
   110→    const edges = await prisma.mapEdge.findMany({
   111→      where: {
   112→        OR: [
   113→          { sourceId: { in: nodeIds } },
   114→          { targetId: { in: nodeIds } },
   115→        ],
   116→      },
   117→    });
   118→
   119→    const result = {
   120→      nodes,
   121→      edges,
   122→      personalizedNodeIds,
   123→      studentBreadthScore: signalProfile?.breadthScore ?? 0,
   124→    };
   125→
   126→    // Cache for 1 hour
   127→    await redis.setex(
   128→      CACHE_KEYS.personalizedMap(student.id),
   129→      CACHE_TTL.personalizedMap,
   130→      result
   131→    );
   132→
   133→    return NextResponse.json(result);
   134→  } catch (error) {
   135→    const message = error instanceof Error ? error.message : "Unknown error";
   136→    return NextResponse.json({ error: message }, { status: 400 });
   137→  }
   138→}
