    47→      },
    48→    });
    49→
    50→    if (!student) {
    51→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    52→    }
    53→
    54→    const privacy = student.privacySettings;
    55→    const profile = student.signalProfiles[0];
    56→
    57→    const filteredProfile = profile
    58→      ? {
    59→          interestClusters:
    60→            privacy?.shareInterestClusters !== false
    61→              ? profile.interestClusters
    62→              : [],
    63→          characterSignals:
    64→            privacy?.shareCharacterSignals !== false
    65→              ? profile.characterSignals
    66→              : [],
    67→          trajectoryShifts:
    68→            privacy?.shareTrajectoryShifts !== false
    69→              ? profile.trajectoryShifts
    70→              : [],
    71→          breadthScore:
    72→            privacy?.shareBreadthScore !== false ? profile.breadthScore : null,
    73→          compressedSummary:
    74→            privacy?.shareInterestClusters !== false
    75→              ? profile.compressedSummary
    76→              : null,
    77→        }
    78→      : null;
    79→
    80→    const sharedReflections = student.sessions.flatMap((s) =>
    81→      s.reflections.map((r) => ({
    82→        ...r,
    83→        monthKey: s.monthKey,
    84→      }))
    85→    );
    86→
    87→    const result = await aiService.getMeetingPrep({
    88→      studentId: student.id,
    89→      counselorId: counselor.id,
    90→      signalProfile: filteredProfile,
    91→      sharedReflections,
    92→    });
    93→
    94→    // Cache for 24 hours
    95→    await redis.setex(cacheKey, CACHE_TTL.meetingPrep, result);
    96→
    97→    return NextResponse.json(result);
    98→  } catch (error) {
    99→    const message = error instanceof Error ? error.message : "Unknown error";
   100→    return NextResponse.json({ error: message }, { status: 400 });
   101→  }
   102→}
