     1→import { NextResponse } from "next/server";
     2→import { requireCounselor } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→
     5→export async function GET() {
     6→  try {
     7→    const counselor = await requireCounselor();
     8→
     9→    const students = await prisma.student.findMany({
    10→      where: { schoolId: counselor.schoolId },
    11→      include: {
    12→        signalProfiles: {
    13→          orderBy: { createdAt: "desc" },
    14→          take: 1,
    15→          select: { breadthScore: true, gapDetection: true },
    16→        },
    17→        sessions: {
    18→          orderBy: { createdAt: "desc" },
    19→          take: 1,
    20→          select: { completedAt: true, createdAt: true },
    21→        },
    22→        privacySettings: true,
    23→      },
    24→    });
    25→
    26→    const now = new Date();
    27→    const flaggedStudents = [];
    28→
    29→    for (const student of students) {
    30→      const flags: string[] = [];
    31→      const lastSession = student.sessions[0];
    32→      const profile = student.signalProfiles[0];
    33→
    34→      // Disengagement flag: no session in 90+ days (or never)
    35→      if (!lastSession?.completedAt) {
    36→        if (!student.onboardingCompleted) {
    37→          flags.push("never_onboarded");
    38→        } else {
    39→          flags.push("never_reflected");
    40→        }
    41→      } else {
    42→        const daysSince = Math.floor(
    43→          (now.getTime() - new Date(lastSession.completedAt).getTime()) /
    44→            (1000 * 60 * 60 * 24)
    45→        );
    46→        if (daysSince > 90) {
    47→          flags.push("disengaged");
    48→        }
    49→      }
    50→
    51→      // Narrow interest flag: breadthScore < 20
    52→      if (
    53→        student.privacySettings?.shareBreadthScore !== false &&
    54→        profile?.breadthScore !== undefined &&
    55→        profile.breadthScore < 20
    56→      ) {
    57→        flags.push("narrow_interests");
    58→      }
    59→
    60→      if (flags.length > 0) {
    61→        flaggedStudents.push({
    62→          id: student.id,
    63→          firstName: student.firstName,
    64→          lastName: student.lastName,
    65→          gradeLevel: student.gradeLevel,
    66→          flags,
    67→          breadthScore:
    68→            student.privacySettings?.shareBreadthScore !== false
    69→              ? profile?.breadthScore
    70→              : null,
    71→          lastSessionDate: lastSession?.completedAt,
    72→        });
    73→      }
    74→    }
    75→
    76→    return NextResponse.json(flaggedStudents);
    77→  } catch (error) {
    78→    const message = error instanceof Error ? error.message : "Unknown error";
    79→    return NextResponse.json({ error: message }, { status: 400 });
    80→  }
    81→}
    82→

