    54→  "Privacy",
    55→];
    56→
    57→export default function SessionWizard({
    58→  session,
    59→  student,
    60→  allActivities,
    61→}: {
    62→  session: Session;
    63→  student: Student;
    64→  allActivities: Activity[];
    65→}) {
    66→  const router = useRouter();
    67→  const [step, setStep] = useState(1);
    68→  const [submitting, setSubmitting] = useState(false);
    69→  const [submitError, setSubmitError] = useState<string | null>(null);
    70→  const [localSession, setLocalSession] = useState(session);
    71→
    72→  const sessionTitle = session.template?.title
    73→    ? `Reflection ${session.template.orderNum}: ${session.template.title}`
    74→    : session.monthKey
    75→    ? new Date(
    76→        parseInt(session.monthKey.split("-")[0]!),
    77→        parseInt(session.monthKey.split("-")[1]!) - 1
    78→      ).toLocaleString("default", { month: "long", year: "numeric" }) + " Reflection"
    79→    : `Reflection ${session.sessionNumber ?? ""}`;
    80→
    81→  const handleSubmit = useCallback(async () => {
    82→    setSubmitting(true);
    83→    setSubmitError(null);
    84→    try {
    85→      const res = await fetch(`/api/sessions/${session.id}/submit`, {
    86→        method: "POST",
    87→      });
    88→      if (res.ok) {
    89→        router.push(`/reflect/${session.id}/complete`);
    90→      } else {
    91→        const data = await res.json().catch(() => null) as { error?: string } | null;
    92→        setSubmitError(data?.error ?? "Something went wrong. Please try again.");
    93→      }
    94→    } catch {
    95→      setSubmitError("Network error. Please check your connection and try again.");
    96→    } finally {
    97→      setSubmitting(false);
    98→    }
    99→  }, [session.id, router]);
   100→
   101→  return (
   102→    <div className="min-h-screen">
   103→      {/* Header */}
   104→      <div className="flex items-center justify-between mb-6">
