   106→          <h1 className="text-lg font-bold text-[#1A1A2E]">
   107→            {sessionTitle}
   108→          </h1>
   109→          <p className="text-xs text-[#6B7280]">Step {step} of 5</p>
   110→        </div>
   111→        <div className="flex items-center gap-1">
   112→          {STEP_LABELS.map((_, i) => (
   113→            <div
   114→              key={i}
   115→              className={`h-1.5 rounded-full transition-all duration-300 ${
   116→                i + 1 < step
   117→                  ? "bg-[#10B981] w-6"
   118→                  : i + 1 === step
   119→                  ? "bg-[#3B82F6] w-8"
   120→                  : "bg-gray-200 w-4"
   121→              }`}
   122→            />
   123→          ))}
   124→        </div>
   125→      </div>
   126→
   127→      {/* Step Content */}
   128→      <AnimatePresence mode="wait">
   129→        <motion.div
   130→          key={step}
   131→          variants={fadeUpVariant}
   132→          initial="hidden"
   133→          animate="visible"
   134→          exit={{ opacity: 0, y: -10 }}
   135→        >
   136→          {step === 1 && (
   137→            <PulseCheckStep
   138→              session={localSession}
   139→              student={student}
   140→              onNext={(data) => {
   141→                setLocalSession((prev) => ({ ...prev, ...data }));
   142→                setStep(2);
   143→              }}
   144→            />
   145→          )}
   146→          {step === 2 && (
   147→            <ActivityLoggerStep
   148→              session={localSession}
   149→              allActivities={allActivities}
   150→              onNext={(activities) => {
   151→                setLocalSession((prev) => ({ ...prev, activities }));
   152→                setStep(3);
   153→              }}
   154→              onBack={() => setStep(1)}
   155→            />
   156→          )}
   157→          {step === 3 && (
   158→            <ReflectionPromptsStep
   159→              session={localSession}
   160→              onNext={(reflections) => {
   161→                setLocalSession((prev) => ({ ...prev, reflections }));
   162→                setStep(4);
   163→              }}
   164→              onBack={() => setStep(2)}
   165→            />
   166→          )}
   167→          {step === 4 && (
   168→            <MapMomentStep
   169→              session={localSession}
   170→              onNext={() => setStep(5)}
   171→              onBack={() => setStep(3)}
   172→            />
   173→          )}
   174→          {step === 5 && (
   175→            <PrivacyReviewStep
   176→              session={localSession}
   177→              onSubmit={handleSubmit}
   178→              onBack={() => setStep(4)}
   179→              submitting={submitting}
   180→              error={submitError}
   181→            />
   182→          )}
   183→        </motion.div>
   184→      </AnimatePresence>
   185→    </div>
   186→  );
   187→}
